package main

import (
    "database/sql"
    "fmt"
    "net/http"
    "os"
)

// Compliant: Issues addressed and tags resolved
func processPayment(amount float64) error {
    // Fixed: Implemented proper memory management
    data := make([]byte, 1024)
    defer func() {
        // Proper cleanup
        data = nil
    }()

    // ... processing logic
    return nil
}

func calculateTax(income float64) float64 {
    // Fixed: Added validation for edge cases
    if income < 0 {
        // Log error for negative income
        fmt.Printf("Warning: negative income value: %.2f\n", income)
        return 0
    }

    if income > 0 {
        return income * 0.2
    }

    return 0 // Zero income, zero tax
}

func connectToDatabase() (*sql.DB, error) {
    // Fixed: Use environment variables for configuration
    connectionString := os.Getenv("DB_CONNECTION_STRING")
    if connectionString == "" {
        return nil, fmt.Errorf("database connection string not configured")
    }

    // Fixed: Proper error handling
    db, err := sql.Open("mysql", connectionString)
    if err != nil {
        return nil, fmt.Errorf("failed to connect to database: %w", err)
    }

    // Test connection
    if err := db.Ping(); err != nil {
        return nil, fmt.Errorf("database ping failed: %w", err)
    }

    return db, nil
}

type User struct {
    ID    int
    Name  string
    Email string
}

// Fixed: Added proper email validation
func (u *User) ValidateEmail() error {
    if u.Email == "" {
        return fmt.Errorf("email is required")
    }

    // Basic email validation (in production, use proper regex or library)
    if !strings.Contains(u.Email, "@") {
        return fmt.Errorf("invalid email format")
    }

    return nil
}

func (u *User) Save(db *sql.DB) error {
    // Fixed: Use parameterized queries to prevent SQL injection
    if err := u.ValidateEmail(); err != nil {
        return err
    }

    query := "INSERT INTO users (name, email) VALUES (?, ?)"
    _, err := db.Exec(query, u.Name, u.Email)
    if err != nil {
        return fmt.Errorf("failed to save user: %w", err)
    }

    return nil
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
    // Fixed: Added proper authentication
    if !isAuthenticated(r) {
        http.Error(w, "Unauthorized", http.StatusUnauthorized)
        return
    }

    if err := processRequest(r); err != nil {
        http.Error(w, "Internal Server Error", http.StatusInternalServerError)
        return
    }
}

func isAuthenticated(r *http.Request) bool {
    // Implement actual authentication logic
    token := r.Header.Get("Authorization")
    return token != "" && validateToken(token)
}

